// =============================================
// VALIDAR ANTI-SPAM + EXTRAIR BODY
// =============================================
const body = $input.item.json.body;

const website = String(body.website || '').trim(); // honeypot
const email   = String(body.email   || '').trim();

const honeypotOk = website === '';
const emailOk    = email !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

console.log('=== ANTI-SPAM DIAGNÓSTICO ===');
console.log('Honeypot vazio?', honeypotOk);
console.log('E-mail válido?', emailOk);

if (!honeypotOk || !emailOk) {
  throw new Error('Validação falhou — possível spam ou e-mail ausente');
}

return body;

// =============================================
// PREPARAR E NORMALIZAR DADOS
// =============================================
const d = $input.item.json;

return {
  email:                 String(d.email                  || '').trim().toLowerCase(),
  gestao_reservas:       String(d.gestao_reservas         || '').trim(),
  reservas_mes:          String(d.reservas_mes            || '').trim(),
  taxa_ocupacao:         String(d.taxa_ocupacao           || '').trim(),
  canais_venda:          String(d.canais_venda            || '').trim(),
  principal_dificuldade: String(d.principal_dificuldade   || '').trim(),
  tem_equipe:            String(d.tem_equipe              || '').trim(),
  impede_crescer:        String(d.impede_crescer          || '').trim(),
  expectativa:           String(d.expectativa             || '').trim(),
  url_origem:            String(d.url_origem              || '').trim()
};
